INSERT INTO stall (id, merchant_id, name, description, logo, location, phone, business_hours, status, avg_rating, monthly_sales, created_at) VALUES
(1, 2, '川味小厨',   '正宗川菜，麻辣鲜香，回味无穷。招牌菜品有宫保鸡丁、麻婆豆腐、水煮鱼等。',             'https://images.unsplash.com/photo-1617196034796-73dfa7b1fd56?w=400&h=300&fit=crop', '一食堂一楼A01', '13800000002', '07:00-21:00', 1, 4.5, 1280, '2025-10-02 10:00:00'),
(2, 3, '兰州拉面',   '手工拉面，汤鲜面劲。一碗热腾腾的牛肉面，温暖你的整个冬天。',                         'https://images.unsplash.com/photo-1555126634-323283e090fa?w=400&h=300&fit=crop', '一食堂一楼A02', '13800000003', '06:30-21:00', 1, 4.3, 1560, '2025-10-03 10:00:00'),
(3, 4, '黄焖鸡米饭', '秘制酱料焖制，鸡肉鲜嫩多汁，米饭粒粒饱满。经典黄焖鸡，百吃不厌。',                   'https://images.unsplash.com/photo-1598515214211-89d3c73ae83b?w=400&h=300&fit=crop', '一食堂二楼B01', '13800000004', '10:00-20:30', 1, 4.2, 980,  '2025-10-05 10:00:00'),
(4, 5, '韩式料理',   '地道韩式风味，石锅拌饭、部队锅、炸鸡等经典韩餐，带你领略韩国美食文化。',               'https://images.unsplash.com/photo-1553163147-622ab57be1c7?w=400&h=300&fit=crop', '二食堂一楼C01', '13800000005', '10:00-21:00', 1, 4.6, 760,  '2025-10-06 10:00:00'),
(5, 6, '饮品甜点',   '新鲜水果茶、奶茶、咖啡及各式甜品，给你的校园生活加点甜。',                             'https://images.unsplash.com/photo-1558857563-b371033873b8?w=400&h=300&fit=crop', '二食堂一楼C02', '13800000006', '08:00-22:00', 1, 4.7, 2100, '2025-10-08 10:00:00'),
(6, 2, '麻辣香锅',   '自选食材，现炒现卖。麻辣、香辣、蒜香多种口味可选，荤素搭配营养均衡。',                 'https://images.unsplash.com/photo-1574484284002-952d92456975?w=400&h=300&fit=crop', '一食堂二楼B02', '13800000002', '10:30-20:30', 1, 4.4, 890,  '2025-10-10 10:00:00'),
(7, 3, '沙县小吃',   '经典沙县风味，蒸饺、拌面、炖罐应有尽有。物美价廉，学生最爱。',                         'https://images.unsplash.com/photo-1496116218417-1a781b1c416c?w=400&h=300&fit=crop', '二食堂二楼D01', '13800000003', '06:30-21:30', 1, 4.1, 1820, '2025-10-12 10:00:00'),
(8, 4, '西式简餐',   '汉堡、意面、牛排、沙拉等西式美食，为你带来不一样的用餐体验。',                         'https://images.unsplash.com/photo-1568901346375-23c9450c58cd?w=400&h=300&fit=crop', '二食堂二楼D02', '13800000004', '09:00-21:00', 0, 0.0, 0,    '2026-01-20 10:00:00');

