-- ============================================================
-- 评价数据（32个）
-- ============================================================
INSERT INTO review (id, order_id, user_id, stall_id, dish_id, rating, content, images, reply_content, reply_at, status, created_at) VALUES
(1,  1,  7,  1, 1,  5, '宫保鸡丁真的太好吃了！花生酥脆，鸡丁嫩滑，麻辣适中，强烈推荐！',           NULL, '感谢您的好评，欢迎再来！',         '2025-10-15 16:00:00', 0, '2025-10-15 12:30:00'),
(2,  1,  7,  1, 2,  4, '麻婆豆腐味道不错，就是有点偏咸了，下次少放点盐就完美了。',                   NULL, '感谢反馈，我们会注意调整口味。',   '2025-10-15 16:05:00', 0, '2025-10-15 12:35:00'),
(3,  2,  8,  2, 9,  5, '牛肉拉面真的很正宗！汤底浓郁，面条劲道，牛肉给的量也很足。',                 NULL, '谢谢支持，我们一直坚持手工拉面。', '2025-10-16 15:00:00', 0, '2025-10-16 13:00:00'),
(4,  3,  9,  5, 26, 5, '珍珠奶茶太赞了，珍珠Q弹，奶茶香浓不腻，以后天天来。',                       NULL, NULL, NULL, 0, '2025-10-17 15:30:00'),
(5,  4,  10, 1, 4,  4, '回锅肉做得很地道，肥而不腻，蒜苗也很新鲜，配米饭绝了。',                     NULL, '谢谢评价，川味小厨欢迎您常来！',   '2025-10-19 10:00:00', 0, '2025-10-18 13:00:00'),
(6,  5,  11, 4, 20, 5, '石锅拌饭太棒了！锅巴脆脆的，蔬菜很新鲜，拌上酱超好吃。',                     NULL, '谢谢您的五星好评！',               '2025-10-21 10:00:00', 0, '2025-10-20 13:30:00'),
(7,  5,  11, 4, 21, 5, '部队锅料很足，拉面和芝士搭配绝了，冬天吃超幸福！',                            NULL, NULL, NULL, 0, '2025-10-20 13:35:00'),
(8,  6,  7,  3, 16, 4, '黄焖鸡大份量确实大，鸡肉很入味，就是稍微油了点。',                            NULL, '感谢建议，我们会适当减少油量。',   '2025-10-23 10:00:00', 0, '2025-10-22 12:30:00'),
(9,  7,  12, 7, 43, 4, '蒸饺皮薄馅多，味道不错，就是要早点去不然容易卖完。',                          NULL, NULL, NULL, 0, '2025-10-25 13:30:00'),
(10, 7,  12, 7, 40, 4, '拌面香喷喷的，花生酱给的足，性价比很高。',                                    NULL, '谢谢光临，我们一直坚持用好料！',   '2025-10-26 09:00:00', 0, '2025-10-25 13:35:00'),
(11, 8,  13, 6, 36, 5, '麻辣香锅太过瘾了！食材新鲜，麻辣味道调得恰到好处，吃完一锅还想再来。',         NULL, '感谢好评！欢迎再来尝试不同口味！', '2025-10-29 10:00:00', 0, '2025-10-28 13:00:00'),
(12, 9,  14, 5, 27, 5, '芋泥波波奶茶yyds！芋泥绵密，波波Q弹，甜度刚好。',                             NULL, NULL, NULL, 0, '2025-11-01 16:00:00'),
(13, 10, 15, 2, 9,  4, '面条很筋道，牛肉也很大块，不过汤有点咸了。',                                  NULL, '感谢反馈，下次可以跟师傅说少盐。', '2025-11-04 10:00:00', 0, '2025-11-03 12:30:00'),
(14, 11, 16, 1, 3,  5, '水煮鱼片鱼肉超嫩，完全不腥，麻辣鲜香，太棒了！',                              NULL, '谢谢您的认可！我们坚持用新鲜鱼。', '2025-11-06 10:00:00', 0, '2025-11-05 13:00:00'),
(15, 12, 17, 4, 20, 4, '石锅拌饭中规中矩，味道还行，酱料可以再丰富一些。',                             NULL, NULL, NULL, 0, '2025-11-08 13:30:00'),
(16, 13, 18, 7, 42, 4, '馄饨面汤鲜味浓，馄饨皮滑馅嫩，很暖胃。',                                     NULL, '谢谢好评，天冷来一碗最合适了！',   '2025-11-11 10:00:00', 0, '2025-11-10 13:00:00'),
(17, 14, 9,  5, 32, 5, '拿铁非常好喝，奶泡细腻，咖啡香醇，可以媲美外面的咖啡店了。',                  NULL, '感谢认可！我们用的是进口咖啡豆。', '2025-11-13 10:00:00', 0, '2025-11-12 15:00:00'),
(18, 14, 9,  5, 33, 5, '提拉米苏入口即化，咖啡味和奶油味融合得刚刚好，太幸福了。',                     NULL, NULL, NULL, 0, '2025-11-12 15:05:00'),
(19, 15, 19, 1, 3,  4, '水煮鱼片很好吃，不过今天感觉辣椒放多了些，嘴巴辣得受不了。',                  NULL, '谢谢反馈，您下次可以备注微辣哦。', '2025-11-16 10:00:00', 0, '2025-11-15 12:30:00'),
(20, 16, 20, 3, 16, 5, '黄焖鸡大份真的很实惠，鸡肉多酱汁浓，米饭都多吃了一碗。',                      NULL, '谢谢！欢迎常来吃！',               '2025-11-19 10:00:00', 0, '2025-11-18 13:00:00'),
(21, 17, 7,  6, 36, 4, '麻辣香锅味道不错，但是今天虾仁感觉不太新鲜，希望改进。',                      NULL, '非常抱歉！我们会加强食材管理。',   '2025-11-21 10:00:00', 0, '2025-11-20 13:30:00'),
(22, 18, 21, 2, 9,  3, '面条稍微有点软了，不过牛肉汤底还是很香的，总体还行吧。',                       NULL, '感谢反馈，我们会控制好煮面时间。', '2025-11-23 10:00:00', 0, '2025-11-22 12:30:00'),
(23, 19, 22, 5, 26, 5, '珍珠奶茶永远的最爱！每次来都必点，品质一直很稳定。',                           NULL, '谢谢您一直的支持！',               '2025-11-26 10:00:00', 0, '2025-11-25 16:00:00'),
(24, 20, 8,  4, 21, 5, '部队锅真的超级好吃！份量大到两个人都吃不完，料很足。',                         NULL, NULL, NULL, 0, '2025-11-28 13:30:00'),
(25, 21, 23, 7, 40, 3, '拌面花生酱有点少了，而且今天面条有点结坨，希望改进。',                         NULL, '抱歉给您带来不好的体验，我们改进！', '2025-12-02 10:00:00', 0, '2025-12-01 13:00:00'),
(26, 22, 10, 1, 4,  5, '回锅肉还是那个味道，百吃不腻！川味小厨出品都很稳定。',                        NULL, '谢谢老顾客的支持！',               '2025-12-04 10:00:00', 0, '2025-12-03 12:30:00'),
(27, 23, 24, 6, 35, 4, '荤菜版麻辣香锅肉量很足，就是等了有点久，希望出餐再快点。',                     NULL, '高峰期出餐确实较慢，我们会优化流程。', '2025-12-06 10:00:00', 0, '2025-12-05 13:30:00'),
(28, 24, 25, 3, 17, 5, '黄焖排骨太好吃了！排骨炖得很烂，酱汁浓郁，米饭吃了两碗。',                    NULL, '感谢好评！排骨是我们的新品，很受欢迎！', '2025-12-09 10:00:00', 0, '2025-12-08 13:00:00'),
(29, 25, 11, 5, 32, 4, '拿铁一如既往的好喝，天冷的时候来一杯热拿铁真的很幸福。',                       NULL, NULL, NULL, 0, '2025-12-10 15:30:00'),
(30, 44, 26, 2, 11, 4, '鸡蛋拉面分量足，汤也很鲜，就是鸡蛋少了点，下次多加个蛋。',                    NULL, '谢谢建议，加蛋只需多2元哦。',     '2026-01-26 10:00:00', 0, '2026-01-25 13:00:00'),
(31, 45, 31, 7, 42, 5, '馄饨面太好吃了！馄饨个头大，面条也很筋道，值得推荐。',                         NULL, '感谢五星好评！欢迎常来！',         '2026-01-29 10:00:00', 0, '2026-01-28 13:00:00'),
(32, 45, 31, 7, 45, 4, '鸡腿炖汤汤头浓郁，鸡腿肉很嫩，就是有点咸，口味淡的可以加汤。',               NULL, NULL, NULL, 0, '2026-01-28 13:05:00'),
-- ========== 2026年2月 评价 ==========
(33, 46, 7,  1, 1,  5, '开学第一餐就来川味小厨，宫保鸡丁还是那个熟悉的味道！',                         NULL, '欢迎回来！新学期多来吃！',         '2026-02-04 10:00:00', 0, '2026-02-03 13:00:00'),
(34, 47, 8,  5, 27, 5, '芋泥波波永远的神！冬天喝热的真的太舒服了。',                                   NULL, NULL, NULL, 0, '2026-02-04 15:30:00'),
(35, 48, 9,  2, 9,  4, '牛肉拉面汤底依然很好喝，面条今天煮得刚刚好。',                                 NULL, '谢谢光临！',                       '2026-02-06 10:00:00', 0, '2026-02-05 13:00:00'),
(36, 49, 10, 4, 23, 5, '韩式炸鸡太绝了！外酥里嫩，配甜辣酱一绝。和石锅拌饭一起点超幸福。',              NULL, '谢谢好评！新学期有新口味哦！',     '2026-02-07 10:00:00', 0, '2026-02-06 13:30:00'),
(37, 50, 11, 6, 36, 4, '麻辣香锅出品质量还是很稳定的，麻辣味道恰到好处。',                              NULL, NULL, NULL, 0, '2026-02-07 13:00:00'),
(38, 52, 13, 1, 3,  5, '水煮鱼片永远是我的最爱！鱼肉嫩滑，汤底麻辣鲜香。',                              NULL, '感谢老顾客支持！',                 '2026-02-11 10:00:00', 0, '2026-02-10 13:00:00'),
(39, 53, 14, 3, 16, 4, '黄焖鸡大份量真的很足，配上米饭吃得很饱，性价比高。',                             NULL, '谢谢评价！欢迎常来！',             '2026-02-13 10:00:00', 0, '2026-02-12 13:00:00'),
(40, 54, 15, 5, 33, 5, '情人节和女朋友来喝咖啡吃提拉米苏，感觉很幸福！',                                 NULL, '祝你们情人节快乐！',               '2026-02-15 10:00:00', 0, '2026-02-14 15:30:00'),
(41, 57, 18, 7, 42, 4, '馄饨面汤鲜味美，冬天来一碗暖暖的。',                                             NULL, NULL, NULL, 0, '2026-02-18 13:00:00'),
(42, 59, 7,  6, 35, 5, '荤菜版香锅虾仁很新鲜！这次品质比上次好很多，满分！',                              NULL, '感谢认可！我们一直在改进！',       '2026-02-23 10:00:00', 0, '2026-02-22 13:30:00'),
(43, 63, 23, 1, 1,  4, '宫保鸡丁花生酥脆，鸡丁嫩滑，不过今天辣了一点。',                                NULL, '谢谢反馈，下次可以备注微辣。',     '2026-02-28 10:00:00', 0, '2026-02-27 13:00:00'),
(44, 64, 24, 2, 9,  5, '牛肉拉面面条很筋道，汤头也很浓郁，吃完一碗还想再来一碗。',                       NULL, '感谢五星好评！',                   '2026-03-01 10:00:00', 0, '2026-02-28 13:00:00'),
-- ========== 2026年3月 评价 ==========
(45, 65, 7,  5, 27, 5, '三月份了还是最爱芋泥波波！品质一直很稳定。',                                     NULL, NULL, NULL, 0, '2026-03-01 11:00:00'),
(46, 68, 8,  4, 21, 5, '部队锅料超足！拉面和芝士搭配绝了！',                                             NULL, NULL, NULL, 0, '2026-03-01 13:30:00');

-- ============================================================
-- 投诉数据（12个）
-- ============================================================
INSERT INTO complaint (id, user_id, stall_id, order_id, type, content, images, status, reply_content, handler_id, handled_at, created_at) VALUES
(1,  7,  1, 1,  1, '宫保鸡丁里吃到了一小块骨头碎片，希望加强食品安全检查。',                           NULL, 2, '非常抱歉给您带来不好的体验，我们已加强食材检查流程，并对相关人员进行了培训。', 1, '2025-10-16 10:00:00', '2025-10-15 13:00:00'),
(2,  8,  2, 2,  2, '点餐时店员态度不太好，问了两次才回答我的问题。',                                   NULL, 2, '非常抱歉，我们已对相关店员进行沟通和培训，后续会加强服务意识。',               1, '2025-10-17 10:00:00', '2025-10-16 13:30:00'),
(3,  14, 5, 9,  4, '奶茶杯盖没盖紧，拿的时候洒出来了，弄到衣服上了。',                                 NULL, 2, '非常抱歉！我们已提醒所有员工注意杯盖密封。可以到店换一杯新的。',             1, '2025-11-02 10:00:00', '2025-11-01 16:00:00'),
(4,  13, 6, 8,  1, '麻辣香锅里面的虾仁感觉不太新鲜，吃完肚子有点不舒服。',                             NULL, 1, NULL, NULL, NULL, '2025-10-28 14:00:00'),
(5,  16, 3, NULL, 3, '黄焖鸡米饭档口前面的地面有点油腻，走路容易滑倒，希望能定期清洁。',               NULL, 2, '感谢反馈，我们已安排人员加强该区域的清洁工作。',                             1, '2025-11-09 10:00:00', '2025-11-08 14:00:00'),
(6,  21, 2, 18, 2, '排了很长时间的队，前面明明没多少人但出餐很慢，效率需要提高。',                      NULL, 2, '非常抱歉，高峰期确实较慢。我们已增加人手，后续会改善出餐效率。',             1, '2025-11-23 10:00:00', '2025-11-22 13:00:00'),
(7,  20, 7, 40, 1, '拌面花生酱有一股哈喇味，怀疑花生酱过期了。',                                      NULL, 2, '非常感谢您的反馈！经核查是当日花生酱临近保质期，已全部更换新批次。',         1, '2025-12-06 10:00:00', '2025-12-05 12:30:00'),
(8,  22, 5, 19, 4, '奶茶里面甜度太高了，我明明备注了少糖，结果跟全糖一样甜。',                          NULL, 2, '抱歉没有按您的要求制作，已提醒店员认真查看备注，欢迎到店重新制作。',         1, '2025-11-26 10:00:00', '2025-11-25 16:30:00'),
(9,  10, 1, 22, 1, '菜里有一根头发，虽然味道不错但影响食欲。',                                         NULL, 2, '非常抱歉！我们已要求所有厨师佩戴厨师帽，加强了卫生管理。',                 1, '2025-12-04 10:00:00', '2025-12-03 13:00:00'),
(10, 9,  4, 29, 2, '韩式料理的服务员上错了菜，等了很久才换过来，影响用餐体验。',                       NULL, 0, NULL, NULL, NULL, '2026-01-08 13:00:00'),
(11, 24, 6, 23, 3, '麻辣香锅档口的桌子上有油渍没清理干净，餐具也不太干净。',                           NULL, 3, '经核查当日已正常清洁，可能是就餐高峰期未及时清理，已加强巡查。',             1, '2025-12-06 15:00:00', '2025-12-05 14:00:00'),
(12, 28, 5, 28, 4, '取餐的时候没有叫号，直接放在窗口，差点被别人拿走了。',                              NULL, 1, NULL, NULL, NULL, '2026-01-07 15:30:00');

-- ============================================================
-- 公告数据（10个）
-- ============================================================
INSERT INTO announcement (id, title, content, type, publisher_id, stall_id, status, published_at, created_at) VALUES
(1,  '校园餐饮管理系统正式上线',        '亲爱的同学们，校园餐饮管理系统已正式上线！您可以通过系统在线浏览菜单、下单点餐、查看评价等。祝大家用餐愉快！',                            0, 1, NULL, 1, '2025-10-01 10:00:00', '2025-10-01 09:00:00'),
(2,  '国庆节食堂营业时间调整通知',       '国庆假期期间（10月1日-10月7日），各食堂营业时间调整为 09:00-19:00，请同学们合理安排用餐时间。',                                           0, 1, NULL, 1, '2025-10-01 08:00:00', '2025-09-30 16:00:00'),
(3,  '川味小厨新品上市',                '川味小厨隆重推出秋季新品——酸菜鱼、钵钵鸡、串串香！即日起至月底，新品一律8折优惠，欢迎品尝！',                                          1, 2, 1,    1, '2025-10-15 08:00:00', '2025-10-14 17:00:00'),
(4,  '关于加强食堂卫生管理的通知',       '为保障师生饮食安全，学校将加强食堂卫生检查力度，实行每日巡检制度。各档口请严格遵守食品安全规范，确保食品卫生安全。',                      0, 1, NULL, 1, '2025-11-01 08:00:00', '2025-10-31 15:00:00'),
(5,  '兰州拉面冬季暖心活动',            '天气转凉，兰州拉面推出"冬日暖心套餐"：牛肉拉面+小菜+酸梅汤，原价23元，套餐价仅需18元！活动持续至12月底。',                              1, 3, 2,    1, '2025-11-10 08:00:00', '2025-11-09 16:00:00'),
(6,  '饮品甜点双十二特惠',              '双十二来啦！饮品甜点全场第二杯半价，满30元送精美小甜品一份。活动时间：12月10日-12月15日，数量有限先到先得！',                              1, 6, 5,    1, '2025-12-10 08:00:00', '2025-12-09 17:00:00'),
(7,  '元旦假期食堂安排',                '元旦假期（1月1日-1月3日），一食堂正常营业，二食堂仅开放一楼。请同学们注意用餐安排，提前做好准备。',                                       0, 1, NULL, 1, '2025-12-30 08:00:00', '2025-12-29 16:00:00'),
(8,  '寒假食堂营业通知',                '寒假期间（1月20日-2月20日），仅一食堂一楼保持营业，营业时间为 08:00-18:00。留校同学请合理安排用餐。',                                     0, 1, NULL, 1, '2026-01-18 08:00:00', '2026-01-17 15:00:00'),
(9,  '西式简餐即将开业',                '好消息！二食堂二楼新增"西式简餐"档口，主打汉堡、意面、沙拉等西式美食，预计2月中旬正式开业，敬请期待！',                                  0, 1, NULL, 1, '2026-01-25 08:00:00', '2026-01-24 15:00:00'),
(10, '韩式料理春季新品预告',             '韩式料理即将推出春季限定新品：芝士年糕火锅、韩式辣炒年糕、紫菜包饭套餐。2月底正式上线，敬请期待！',                                     1, 5, 4,    0, NULL,                   '2026-02-01 10:00:00');

