INSERT INTO activity (id, stall_id, title, description, image, discount_type, discount_value, min_amount, start_time, end_time, status, created_at) VALUES
(1, 1, '川味小厨开业优惠',       '新店开业，全场菜品8折优惠，欢迎品尝正宗川菜！',                             NULL, 2, 8.00,  0.00,  '2025-10-02 00:00:00', '2025-10-15 23:59:59', 2, '2025-10-01 10:00:00'),
(2, 2, '兰州拉面满减活动',       '消费满20元减3元，满35元减6元，多吃多优惠！',                                NULL, 1, 3.00,  20.00, '2025-11-01 00:00:00', '2025-11-30 23:59:59', 2, '2025-10-28 10:00:00'),
(3, 5, '饮品甜点第二杯半价',     '所有饮品第二杯半价，和朋友一起来享受下午茶时光吧！',                         NULL, 2, 5.00,  0.00,  '2025-12-10 00:00:00', '2025-12-15 23:59:59', 2, '2025-12-08 10:00:00'),
(4, 4, '韩式料理满减优惠',       '消费满30元减5元，满50元减10元，感受地道韩味！',                              NULL, 1, 5.00,  30.00, '2026-01-01 00:00:00', '2026-01-31 23:59:59', 2, '2025-12-28 10:00:00'),
(5, 7, '沙县小吃新年特惠',       '新年期间全场满15元送卤蛋一个，满25元送卤鸡腿一个！',                        NULL, 3, 1.00,  15.00, '2026-01-25 00:00:00', '2026-02-10 23:59:59', 1, '2026-01-22 10:00:00'),
(6, 6, '麻辣香锅情人节特惠',     '情人节特别活动！双人套餐立减8元，让麻辣为爱情加温！',                       NULL, 1, 8.00,  50.00, '2026-02-14 00:00:00', '2026-02-14 23:59:59', 0, '2026-02-01 10:00:00'),
(7, 1, '川味小厨春节限定',       '春节限定菜单上线！凡消费满40元赠送秘制小吃一份。',                          NULL, 3, 1.00,  40.00, '2026-02-01 00:00:00', '2026-02-15 23:59:59', 1, '2026-01-28 10:00:00'),
(8, 3, '黄焖鸡冬日暖心活动',     '冬日暖心，黄焖鸡全系列9折优惠，温暖你的每一餐！',                          NULL, 2, 9.00,  0.00,  '2026-02-05 00:00:00', '2026-02-28 23:59:59', 1, '2026-02-03 10:00:00');

